import React, {useState, useEffect, useRef} from 'react'
import styled from 'styled-components'
import {getDesigner, getCategory, getSubCategory} from '../WebAPI'
import {DropdownMenu} from './utils'

const NavBarWrapper = styled.div `
width:90vw;
margin:0 auto;
height:30px;
display:flex;
justify-content:space-between;
align-items:center;
font-size:0.9rem;
padding:5px;
`

const DropDownWrapper = styled.div `
padding:20px 40px;
width:90%;
height:300px;
top:140px;
bottom:0;
left:0;
right:0;
margin:0 auto;
border-radius:0 0 3px 3px;
display:none;
align-items:center;
justidy-content:space-between;
position:absolute;
color:#1C1C1C;
background-color:white;
z-index:3;
filter: drop-shadow(0px 25px 20px rgba(200,200,200,.4));
&:hover {
	display:flex;
}
`

const Line = styled.div `
height:1px;
width:100vw;
background-color:rgba(0, 0, 0, 0.2);
`

const Designers = styled.div `
line-height:40px;
&:hover {
	cursor:pointer;
}

&:hover ${DropDownWrapper} {
	display:flex;
}
`
const MensWear = styled.div `
line-height:40px;
&:hover {
	cursor:pointer;
}
`
const WomensWear = styled.div `
line-height:40px;
&:hover {
	cursor:pointer;
}
`
const StaffPicks = styled.div `
line-height:40px;
&:hover {
	cursor:pointer;
	color:grey;
}
`
const Articles = styled.div `
line-height:40px;
&:hover {
	cursor:pointer;
	color:grey;
}
`

const Title = styled.div `
font-size:1.3rem;
font-weight:200;
`

const Designer = styled.div `
width:20%;
font-size:1rem;
margin:4px 10px;
display:inline-block;
&:hover {
	cursor:pointer;
	color:grey;
}
`

const DesignerWrapper = styled.div `
display:flex;
flex-direction:column;
height:300px;
width:1000px;
margin:0 auto;
flex-wrap:wrap;
`

const Button = styled.div `
`

const Arrow = styled.div `
background-color:#1C1C1C;
clip-path: polygon(40% 0, 75% 0%, 100% 50%, 75% 100%, 40% 100%, 63% 50%);
width:10px;
height:10px;
`

const SubDropdownMenu = styled(DropdownMenu) `
margin-left:180px;

`

const ButtonWrapper = styled.div `
display:flex;
justify-content:space-between;
align-items:center;
width:150px;
&:hover {
	cursor:pointer;
	color:grey;
}
&:hover ${Arrow} {
	cursor:pointer;
	background-color:grey;
}
&:hover ${SubDropdownMenu} {
	display:flex;
}
`

const SubButtonWrapper = styled(ButtonWrapper) ``

export default function Navbar () {
	const [isActive, setIsActive] = useState({
		menswear:false,
		womenswear:false,
		StaffPicks:false,
		Articles:false
	})
	const [category, setCategory] = useState([{}])
	const [designer, setDesigner] = useState([{}])
	const [subCategory, setSubCategory] = useState([{}])

	useEffect(() => {
		getDesigner(setDesigner)
		getCategory(setCategory)
		getSubCategory(setSubCategory)
	},[])

	const onMenswearOver = () => {
		setIsActive({...isActive, menswear:true})
	}

	const onMenswearLeave= () => {
		setIsActive({...isActive, menswear:false})
	}

	const onWomenswearOver = () => {
		setIsActive({...isActive, womenswear:true})
	}

	const onWomenswearLeave = () => {
		setIsActive({...isActive, womenswear:false})
	}


	return (
		<>
		<Line />
		<NavBarWrapper>
			<Designers>DESIGNERS
			<DropDownWrapper>
				<Title>Designers A-Z</Title>
				<DesignerWrapper>
					{designer.map(designer => <Designer key={`${designer.id}:${designer.index}`}>{designer.name}</Designer>)}
				</DesignerWrapper>
			</DropDownWrapper>
			</Designers>
			<MensWear onMouseOver={onMenswearOver} onMouseLeave={onMenswearLeave}>MENSWEAR
				<DropdownMenu isActive={isActive.menswear}>
					{category.filter(category => category.department_id === 1).map(category => 
					<ButtonWrapper key={`${category.id}:${category.index}`}>
						<Button>{category.name}</Button>
						<Arrow/>
					</ButtonWrapper>
					)}
				</DropdownMenu>
				<SubDropdownMenu >
					{subCategory.filter(subCategory => subCategory.category_id === 1).map(subCategory => 
					<ButtonWrapper key={`${subCategory.id}:${subCategory.index}`}>
						<Button>{category.name}</Button>
						<Arrow/>
					</ButtonWrapper>
					)}
				</SubDropdownMenu>
			</MensWear>
			<WomensWear onMouseOver={onWomenswearOver} onMouseLeave={onWomenswearLeave}>WOMENSWEAR
				<DropdownMenu isActive={isActive.womenswear}>
					{category.filter(category => category.department_id === 2).map(category => 
					<SubButtonWrapper key={`${category.id}:${category.index}`}>
						<Button>123344</Button>
						<Arrow/>
					</SubButtonWrapper>	
					)}
				</DropdownMenu>
			</WomensWear>
			<StaffPicks>STAFF PICKS</StaffPicks>
			<Articles>ARTICLES</Articles>
		</NavBarWrapper>
		<Line />
		</>


	)
}
